UNLOCK TABLES;
DROP TABLE IF EXISTS `initial_requirement_files`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `initial_requirement_files` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `application_id` bigint(20) unsigned NOT NULL,
  `requirement_type_id` bigint(20) unsigned NOT NULL,
  `file_path` varchar(255) NOT NULL,
  `original_name` varchar(255) NOT NULL,
  `mime_type` varchar(120) DEFAULT NULL,
  `file_size` bigint(20) unsigned DEFAULT NULL,
  `review_status` varchar(40) NOT NULL DEFAULT 'pending',
  `reviewer_remarks` text DEFAULT NULL,
  `reviewed_by_user_id` bigint(20) unsigned DEFAULT NULL,
  `reviewed_at` datetime DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `fk_requirement_files_application` (`application_id`),
  KEY `fk_requirement_files_type` (`requirement_type_id`),
  KEY `fk_requirement_files_reviewed_by` (`reviewed_by_user_id`),
  CONSTRAINT `fk_requirement_files_application` FOREIGN KEY (`application_id`) REFERENCES `applications` (`id`),
  CONSTRAINT `fk_requirement_files_reviewed_by` FOREIGN KEY (`reviewed_by_user_id`) REFERENCES `users` (`id`),
  CONSTRAINT `fk_requirement_files_type` FOREIGN KEY (`requirement_type_id`) REFERENCES `initial_requirement_types` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=27 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `initial_requirement_files` WRITE;
/*!40000 ALTER TABLE `initial_requirement_files` DISABLE KEYS */;
