DROP TABLE IF EXISTS `post_approval_submissions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `post_approval_submissions` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `post_approval_task_id` bigint(20) unsigned NOT NULL,
  `submission_kind` varchar(40) NOT NULL DEFAULT 'form',
  `file_path` varchar(255) DEFAULT NULL,
  `original_name` varchar(255) DEFAULT NULL,
  `payload_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`payload_json`)),
  `submitted_by_user_id` bigint(20) unsigned DEFAULT NULL,
  `review_status` varchar(40) NOT NULL DEFAULT 'Submitted',
  `reviewer_remarks` text DEFAULT NULL,
  `reviewed_by_user_id` bigint(20) unsigned DEFAULT NULL,
  `submitted_at` datetime DEFAULT NULL,
  `reviewed_at` datetime DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `fk_post_approval_submissions_task` (`post_approval_task_id`),
  KEY `fk_post_approval_submissions_submitted_by` (`submitted_by_user_id`),
  KEY `fk_post_approval_submissions_reviewed_by` (`reviewed_by_user_id`),
  CONSTRAINT `fk_post_approval_submissions_reviewed_by` FOREIGN KEY (`reviewed_by_user_id`) REFERENCES `users` (`id`),
  CONSTRAINT `fk_post_approval_submissions_submitted_by` FOREIGN KEY (`submitted_by_user_id`) REFERENCES `users` (`id`),
  CONSTRAINT `fk_post_approval_submissions_task` FOREIGN KEY (`post_approval_task_id`) REFERENCES `post_approval_tasks` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=22 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `post_approval_submissions` WRITE;
