CREATE TABLE `post_approval_tasks` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `beneficiary_profile_id` bigint(20) unsigned NOT NULL,
  `task_type_id` bigint(20) unsigned NOT NULL,
  `due_date` date DEFAULT NULL,
  `status` varchar(40) NOT NULL DEFAULT 'Unlocked',
  `form_payload` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`form_payload`)),
  `applicant_started_at` datetime DEFAULT NULL,
  `applicant_submitted_at` datetime DEFAULT NULL,
  `reviewed_by_user_id` bigint(20) unsigned DEFAULT NULL,
  `reviewed_at` datetime DEFAULT NULL,
  `reviewer_remarks` text DEFAULT NULL,
  `assigned_by_user_id` bigint(20) unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_post_approval_tasks_beneficiary_task` (`beneficiary_profile_id`,`task_type_id`),
  KEY `fk_post_approval_tasks_type` (`task_type_id`),
  KEY `fk_post_approval_tasks_user` (`assigned_by_user_id`),
  KEY `fk_post_approval_tasks_reviewed_by` (`reviewed_by_user_id`),
  CONSTRAINT `fk_post_approval_tasks_beneficiary` FOREIGN KEY (`beneficiary_profile_id`) REFERENCES `beneficiary_profiles` (`id`),
  CONSTRAINT `fk_post_approval_tasks_reviewed_by` FOREIGN KEY (`reviewed_by_user_id`) REFERENCES `users` (`id`),
  CONSTRAINT `fk_post_approval_tasks_type` FOREIGN KEY (`task_type_id`) REFERENCES `post_approval_task_types` (`id`),
  CONSTRAINT `fk_post_approval_tasks_user` FOREIGN KEY (`assigned_by_user_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=21442 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

