CREATE TABLE `staff_profiles` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint(20) unsigned NOT NULL,
  `contact_number` varchar(40) DEFAULT NULL,
  `position_title` varchar(120) DEFAULT NULL,
  `status` varchar(40) NOT NULL DEFAULT 'active',
  `training_group_number` tinyint(3) unsigned DEFAULT NULL,
  `signature_file_path` varchar(255) DEFAULT NULL,
  `signature_original_name` varchar(255) DEFAULT NULL,
  `signature_mime_type` varchar(120) DEFAULT NULL,
  `signature_file_size` int(10) unsigned DEFAULT NULL,
  `signature_uploaded_at` datetime DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `user_id` (`user_id`),
  CONSTRAINT `fk_staff_profiles_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
