/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `stage_one_registrations` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `reference_code` varchar(40) NOT NULL,
  `first_name` varchar(80) NOT NULL,
  `middle_name` varchar(80) DEFAULT NULL,
  `last_name` varchar(80) NOT NULL,
  `full_name` varchar(180) NOT NULL,
  `email` varchar(160) NOT NULL,
  `contact_number` varchar(40) NOT NULL,
  `complete_address` text NOT NULL,
  `business_photo_path` varchar(255) NOT NULL,
  `business_photo_original_name` varchar(255) NOT NULL,
  `business_photo_mime_type` varchar(120) DEFAULT NULL,
  `business_photo_file_size` bigint(20) unsigned DEFAULT NULL,
  `valid_id_path` varchar(255) NOT NULL,
  `valid_id_original_name` varchar(255) NOT NULL,
  `valid_id_mime_type` varchar(120) DEFAULT NULL,
  `valid_id_file_size` bigint(20) unsigned DEFAULT NULL,
  `validation_status` varchar(40) NOT NULL DEFAULT 'pending',
  `validated_by_user_id` bigint(20) unsigned DEFAULT NULL,
  `validated_at` datetime DEFAULT NULL,
  `selection_email_sent_at` datetime DEFAULT NULL,
  `selection_email_failed_at` datetime DEFAULT NULL,
  `selection_email_error` text DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `reference_code` (`reference_code`),
  KEY `fk_stage_one_registrations_reviewer` (`validated_by_user_id`),
  KEY `idx_stage_one_registrations_status` (`validation_status`),
  KEY `idx_stage_one_registrations_email` (`email`),
  KEY `idx_stage_one_registrations_created_at` (`created_at`),
  CONSTRAINT `fk_stage_one_registrations_reviewer` FOREIGN KEY (`validated_by_user_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=16 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
